import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enable SKAdNetwork","description":"","frontmatter":{"title":"Enable SKAdNetwork","slug":"enable-skadnetwork"},"headers":[],"relativePath":"marketer-hub/enable-skadnetwork.md","filePath":"marketer-hub/enable-skadnetwork.md"}'),n={name:"marketer-hub/enable-skadnetwork.md"};function i(s,e,l,p,d,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Easily set up SKAdNetwork (SKAN) with Branch through a quick-and-easy Magic Setup or configure granular settings yourself all through the Branch SKAN Conversion Center.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to implement SKAdNetwork via the Branch SDK, you must have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Ads for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the latest version of the <a href="./ios-sdk-overview.html">Branch iOS SDK</a> into your mobile app. Your development team will need to implement Apple&#39;s StoreKit Framework and track events. See our <a href="./native-sdks-overview.html">developer documentation</a> for SDK implementation details.</p></li><li><p>Add your app to the Apple App Store.</p><ul><li><p>Admin access to <a href="https://appstoreconnect.apple.com/" target="_blank" rel="noreferrer">App Store Connect</a>.</p><ul><li><strong>Note</strong>: Branch currently does not support using the same iOS App Store ID across multiple Branch apps. This limitation exists because Branch&#39;s SKAN implementation requires a 1:1 mapping between each iOS App Store ID and Branch App ID. <strong>Exception</strong>: Test apps may use the same iOS App Store ID as production apps.</li></ul></li></ul></li><li><p>Ensure your network/publishers support SKAdNetwork and pass attribution data to Branch.</p><ul><li>Verify your ad network(s) <a href="./skadnetwork.html">here</a>.</li><li>Campaign types within that ad network are supported by SKAN.</li><li>Utilizing Branch <a href="./ad-links.html">Ad Links</a> in SKAN Campaigns.</li></ul></li></ol><h2 id="_1-obtain-authentication-parameters" tabindex="-1">1. Obtain authentication parameters <a class="header-anchor" href="#_1-obtain-authentication-parameters" aria-label="Permalink to &quot;1. Obtain authentication parameters&quot;">​</a></h2><p>You will need to obtain several IDs and a key from your <a href="https://appstoreconnect.apple.com/" target="_blank" rel="noreferrer"><strong>Apple App Store</strong> Connect</a>:</p><table tabindex="0"><thead><tr><th>ID</th><th>Definition</th><th>Example</th></tr></thead><tbody><tr><td>Issuer ID</td><td>Your issuer ID from the API Keys page in App Store Connect.</td><td>57246542-96fe-1a63-e053-0824d011072a</td></tr><tr><td>Key ID</td><td>Your private key ID from App Store Connect.</td><td>2X9R4HXF34</td></tr><tr><td>Private Key</td><td>Your key file that authorizes access to your data in App Store Connect and the Apple Developer website.</td><td>P8 Key File</td></tr></tbody></table><p>In the App Store Connect in <strong>Users and Access</strong> → <strong>Keys</strong> tab, find your <strong>Issuer ID</strong> and <strong>Key ID</strong>. Click <strong>Download API key</strong> to obtain your <strong>Private Key</strong>.</p><div class="info custom-block"><p class="custom-block-title">Generate API Key</p><p>If you have not created an API key, click the <strong>+</strong> button to generate a new API Key. Full details for creating API Keys for App Store Connect API can be found <a href="https://developer.apple.com/documentation/appstoreconnectapi/creating_api_keys_for_app_store_connect_api" target="_blank" rel="noreferrer">here</a>.</p></div><h2 id="_2-authenticate-app-store-connect" tabindex="-1">2. Authenticate App Store Connect <a class="header-anchor" href="#_2-authenticate-app-store-connect" aria-label="Permalink to &quot;2. Authenticate App Store Connect&quot;">​</a></h2><p>In the Branch Dashboard navigate to the <strong>SKAN Conversion Center</strong> page. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/skan-conversion" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>Here, you&#39;ll submit your <strong>Issuer ID</strong>, <strong>Key ID</strong>, and <strong>Private Key</strong> that you obtained from <a href="./enable-skadnetwork.html#1-obtain-authentication-parameters">Step 1</a>.</p><p>Click <strong>Save &amp; Continue</strong>.</p><p>Once your App Store Connect account is authenticated (denoted by a green checkmark), please verify the correct app has been synced.</p><div class="info custom-block"><p class="custom-block-title">App Store Connect Credentials</p><p>App Store Connect credentials are used as a one-time check to verify app ownership.</p><p><strong>DO NOT</strong> remove API access as it will disable the ability to map conversion values.</p></div><h2 id="_3-opt-in-out-for-sdk-support" tabindex="-1">3. Opt-in/out for SDK support <a class="header-anchor" href="#_3-opt-in-out-for-sdk-support" aria-label="Permalink to &quot;3. Opt-in/out for SDK support&quot;">​</a></h2><p>By default, your configuration will be set to SDK Opt-In, meaning the Branch SDK will call the two necessary Apple methods for SKAN to enable Postbacks to ad partners on your behalf. You may update this by clicking the options menu on the top right of the SKAN Conversion Center page and selecting <strong>Opt-out SKAdNetwork</strong>.</p><p>We suggest opting out if you have a third-party library or SKAN integration. You&#39;ll still be able to map your conversion value events that will also appear within the Branch Dashboard. Note: Once opted out, the Branch SDK will stop updating SKAN postback conversion values. If you opt out, your development team will need to implement the necessary Apple methods and define conversion values. See our developer documentation for implementation details.</p><h2 id="_4-select-set-up-type" tabindex="-1">4. Select set up type <a class="header-anchor" href="#_4-select-set-up-type" aria-label="Permalink to &quot;4. Select set up type&quot;">​</a></h2><p>From here, you will be prompted to select a set up type: <strong>Magic Set Up</strong> or <strong>Custom Set Up</strong>.</p><table tabindex="0"><thead><tr><th>Set Up Type</th><th>Description</th></tr></thead><tbody><tr><td>Magic Set Up</td><td>Configure SKAN with a Branch-recommended conversion set up to help you get up and running with SKAN quickly while maximizing campaign performance. Recommended for those brand new to SKAN.</td></tr><tr><td>Custom Set Up</td><td>Set granular SKAN configurations like fine/coarse-grained values, anchoring, etc. If you&#39;ve already set up SKAN, your prior set up will be converted over to Custom Set Up. Recommended for those familiar with SKAN already.</td></tr></tbody></table><h3 id="magic-set-up" tabindex="-1">Magic set up <a class="header-anchor" href="#magic-set-up" aria-label="Permalink to &quot;Magic set up&quot;">​</a></h3><h4 id="select-target-conversion-event" tabindex="-1">Select target conversion event <a class="header-anchor" href="#select-target-conversion-event" aria-label="Permalink to &quot;Select target conversion event&quot;">​</a></h4><p>After selecting <strong>Magic Set Up</strong>, you will be prompted to select a target conversion event. It is recommended you select a conversion event that is meaningful for your specific app&#39;s use case that demonstrates customer value.</p><h4 id="review-recommendations" tabindex="-1">Review recommendations <a class="header-anchor" href="#review-recommendations" aria-label="Permalink to &quot;Review recommendations&quot;">​</a></h4><p>Once a conversion event is selected, click <strong>Run Magic Set Up</strong>, and Branch will generate a recommendation for each SKAN window for you.</p><p>Click <strong>Save Configuration</strong> to confirm your SKAN setup.</p><h3 id="custom-set-up" tabindex="-1">Custom set up <a class="header-anchor" href="#custom-set-up" aria-label="Permalink to &quot;Custom set up&quot;">​</a></h3><p>After selecting <strong>Custom Set Up</strong>, you will be able to set an event to a fine-grained value in each of the three windows available for SKAN postbacks.</p><h4 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h4><p>Optionally, you can select a template to preset SKAN for a specific vertical and Branch will help optimize for that. You may choose a template by clicking the <strong>Try now</strong> or <strong>See Templates</strong> link.</p><table tabindex="0"><thead><tr><th>Template Type</th><th>Optimization Focus</th><th>Events</th></tr></thead><tbody><tr><td>Basic</td><td>Generic mobile apps</td><td>Install Open</td></tr><tr><td>Commerce</td><td>Commerce-focused mobile apps</td><td>Install Add to Cart Purchase</td></tr><tr><td>Media</td><td>Media streaming apps</td><td>Install Initiate Stream Complete Stream</td></tr><tr><td>Game</td><td>Gaming apps</td><td>Install Complete Tutorial Achieve Level Spend Credits</td></tr><tr><td>Subscription</td><td>Subscription-based apps</td><td>Install Complete Registration Start Trial Subscribe</td></tr><tr><td>Revenue Ranges</td><td>Distinct purchase-focused apps</td><td>Install Purchase</td></tr></tbody></table><p>At any time, you may revert your configuration to a preset template.</p><h4 id="assign-events" tabindex="-1">Assign events <a class="header-anchor" href="#assign-events" aria-label="Permalink to &quot;Assign events&quot;">​</a></h4><p>Assign an event to a <em>Fine-Grained Value</em>. For each event set to a fine-grained value, assign a <em>Coarse-Grained Value</em>.</p><div class="tip custom-block"><p class="custom-block-title">Fine &amp; Coarse Conversion Values</p><p>A fine value is the fine-grained value of an event that is tied to a value from 0-63 (63 being the highest priority conversion). In SKAN 4.0, this value is sent in the first postback for Tier 2 and 3 thresholds.</p><p>A coarse value indicates a broader signal of the level of priority that that conversion falls under (where the fine value is not eligible for use): low, medium, or high. This is only available for SKAN 4.0+ and is sent in the first postback for the Tier 1 threshold and in the second and third postbacks of Tier 1-3 thresholds.</p><p>For additional details on Postbacks and Tier thresholds, please visit Apple&#39;s documentation <a href="https://developer.apple.com/documentation/storekit/skadnetwork/receiving_postbacks_in_multiple_conversion_windows/" target="_blank" rel="noreferrer">here</a>.</p></div><div class="info custom-block"><p class="custom-block-title">SKAN 4.0+</p><p>If you already had SKAN set up before the release of SKAN 4, you will not have coarse conversion values set for your configuration. By default, a coarse value of &quot;low&quot; is set when not initially defined (&lt; SKAN 3). Making changes to the Event and Conversion Value Mapping will <strong>require</strong> you to select a coarse value and lock option for each event <strong>before</strong> you can save the configuration.</p></div><h4 id="revenue-range" tabindex="-1">Revenue range <a class="header-anchor" href="#revenue-range" aria-label="Permalink to &quot;Revenue range&quot;">​</a></h4><p>Revenue range is available for all <a href="./track-branch-events.html">Commerce Events</a>:</p><ul><li>Revenue must be entered as USD.</li><li>Revenue ranges must not overlap for the same event (Ex. 1-100 and 50-150).</li><li>Lower bound is <em>inclusive</em>, Upper bound is <em>exclusive</em>.</li></ul><h4 id="locking-events" tabindex="-1">Locking events <a class="header-anchor" href="#locking-events" aria-label="Permalink to &quot;Locking events&quot;">​</a></h4><p>For SKAN 4.0+, you are allowed to indicate which events are &quot;locking&quot; events - which means that when that event is detected, it will trigger the SKAN postback and &quot;end&quot; the current SKAN window.</p><h4 id="anchor-highest-value" tabindex="-1">Anchor highest value <a class="header-anchor" href="#anchor-highest-value" aria-label="Permalink to &quot;Anchor highest value&quot;">​</a></h4><p>For SKAN 4.0+, the conversion value mapper supports the ability to anchor to the highest value which means that Branch will guarantee that the highest value event in your mapping that a user completes will be the event sent to SKAN.</p><p>Click <strong>Save Configuration</strong> to confirm your settings and view your settings for each window.</p><h2 id="_5-verify-integration" tabindex="-1">5. Verify integration <a class="header-anchor" href="#_5-verify-integration" aria-label="Permalink to &quot;5. Verify integration&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">SKAN Data Availability &amp; Reporting</p><p>SKAN does not attribute conversions in real-time. Postbacks sent/recieved abide by the <a href="./skadnetwork.html">SKAdNetwork Event Flow</a>.</p><p>Additionally, you can view your full guide on all SKAdNetwork-related reporting <a href="./skadnetwork-dashboard-reports.html">here</a>.</p></div><ol><li><p>Set up a test campaign with the <a href="./skadnetwork.html">participating ad network</a>. Please note that your app will need to be in production and not in Testflight or any other testing platform.</p></li><li><p>Download an Apple SKAdNework Testing Profile to decrease the time in which the postback is sent from a test device from 24 hours to 5-10 minutes.</p><ul><li>See Apple documentation <a href="https://developer.apple.com/documentation/adattributionkit/testing-ad-attributions-with-a-downloaded-profile" target="_blank" rel="noreferrer">here</a> for instructions.</li></ul></li><li><p>Check the <a href="https://dashboard.branch.io/ads/skadnetwork/activity" target="_blank" rel="noreferrer">SKAdNetwork Analytics page</a> to verify SKAdNetwork data.</p></li></ol><p>Additionally, you can verify with your Ad Network the data that they are receiving are proper postbacks for the SKAN campaigns. For advanced testing and troubleshooting, see our developer documentation.</p>',50)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
